+    #[test]
+    fn broadcast_shape_is_commutative_for_sample_shapes() {
+        let shapes: &[&[usize]] = &[
+            &[],
+            &[1],
+            &[3],
+            &[1, 4],
+            &[2, 1, 4],
+            &[2, 3, 4],
+            &[1, 1, 5, 1],
+        ];
+
+        for lhs in shapes {
+            for rhs in shapes {
+                let ab = broadcast_shape(lhs, rhs);
+                let ba = broadcast_shape(rhs, lhs);
+                match (ab, ba) {
+                    (Ok(left), Ok(right)) => assert_eq!(left, right),
+                    (Err(_), Err(_)) => {}
+                    (left, right) => assert_eq!(
+                        left.is_ok(),
+                        right.is_ok(),
